import { Component, type ErrorInfo, type ReactNode } from "react";

interface Props {
  children: ReactNode;
  fallback?: ReactNode;
}

interface State {
  hasError: boolean;
  error: Error | null;
}

export class ErrorBoundary extends Component<Props, State> {
  constructor(props: Props) {
    super(props);
    this.state = { hasError: false, error: null };
  }

  static getDerivedStateFromError(error: Error): State {
    return { hasError: true, error };
  }

  componentDidCatch(error: Error, info: ErrorInfo) {
    console.error("[ErrorBoundary]", error, info.componentStack);
  }

  render() {
    if (this.state.hasError) {
      if (this.props.fallback) return this.props.fallback;

      return (
        <div className="min-h-screen bg-brand-dark flex flex-col items-center justify-center gap-4 p-8">
          <div className="w-16 h-16 rounded-full bg-brand-red/20 flex items-center justify-center">
            <span className="text-3xl">⚠️</span>
          </div>
          <h1 className="text-xl font-bold text-white">Algo salió mal</h1>
          <p className="text-sm text-gray-400 max-w-md text-center">
            Ocurrió un error inesperado. Probá recargar la página.
          </p>
          <pre className="text-xs text-red-400 bg-black/30 p-4 rounded-lg max-w-lg overflow-auto mt-2">
            {this.state.error?.message}
          </pre>
          <button
            onClick={() => window.location.reload()}
            className="mt-4 px-6 py-2 bg-brand-red text-white rounded-lg hover:bg-red-700 transition-colors"
          >
            Recargar página
          </button>
        </div>
      );
    }

    return this.props.children;
  }
}

import { StrictMode } from "react";
import { createRoot } from "react-dom/client";
import { QueryClient, QueryClientProvider } from "@tanstack/react-query";
import { HelmetProvider } from "react-helmet-async";
import { ErrorBoundary } from "@/components/ErrorBoundary";
import "./index.css";
import App from "./App";

const queryClient = new QueryClient({
  defaultOptions: {
    queries: {
      staleTime: 5 * 60 * 1000, // 5 minutes
      retry: 1,
    },
  },
});

createRoot(document.getElementById("root")!).render(
  <StrictMode>
    <ErrorBoundary>
      <HelmetProvider>
        <QueryClientProvider client={queryClient}>
          <App />
        </QueryClientProvider>
      </HelmetProvider>
    </ErrorBoundary>
  </StrictMode>
);

import { lazy, Suspense } from "react";
import { BrowserRouter, Routes, Route, Outlet } from "react-router-dom";
import { Toaster } from "sonner";
import Navbar from "@/components/Navbar";
import Footer from "@/components/Footer";
import ProtectedRoute from "@/components/ProtectedRoute";
import { ErrorBoundary } from "@/components/ErrorBoundary";

// Lazy-loaded public pages — split into route-level chunks for smaller initial bundle
const Home = lazy(() => import("@/pages/Home"));
const Movies = lazy(() => import("@/pages/Movies"));
const Sports = lazy(() => import("@/pages/Sports"));
const Events = lazy(() => import("@/pages/Events"));
const TvLive = lazy(() => import("@/pages/TvLive"));
const SeriesList = lazy(() => import("@/pages/SeriesList"));
const MovieDetail = lazy(() => import("@/pages/MovieDetail"));
const SeriesDetail = lazy(() => import("@/pages/SeriesDetail"));
const Search = lazy(() => import("@/pages/Search"));
const Player = lazy(() => import("@/pages/Player"));
const MoviePlayer = lazy(() => import("@/pages/player/MoviePlayer"));
const SeriesPlayer = lazy(() => import("@/pages/player/SeriesPlayer"));
const NotFound = lazy(() => import("@/pages/NotFound"));
const AdminLogin = lazy(() => import("@/pages/admin/Login"));
const SagaPage = lazy(() => import("@/pages/SagaPage"));

// Lazy-loaded admin pages
const AdminDashboard = lazy(() => import("@/pages/admin/Dashboard"));
const AdminImport = lazy(() => import("@/pages/admin/Import"));
const ManageMovies = lazy(() => import("@/pages/admin/ManageMovies"));
const ManageSeries = lazy(() => import("@/pages/admin/ManageSeries"));
const SportChannels = lazy(() => import("@/pages/admin/SportChannels"));
const EventChannels = lazy(() => import("@/pages/admin/EventChannels"));
const TmdbScraper = lazy(() => import("@/pages/admin/TmdbScraper"));
const VidsrcScanner = lazy(() => import("@/pages/admin/VidsrcScanner"));
const SagaManager = lazy(() => import("@/pages/admin/SagaManager"));

function PageFallback() {
  return (
    <div className="min-h-screen bg-brand-dark flex items-center justify-center">
      <div className="w-8 h-8 border-2 border-brand-red border-t-transparent rounded-full animate-spin" />
    </div>
  );
}

function PublicLayout() {
  return (
    <>
      <Navbar />
      <ErrorBoundary>
        <Suspense fallback={<PageFallback />}>
          <Outlet />
        </Suspense>
      </ErrorBoundary>
      <Footer />
    </>
  );
}

export default function App() {
  return (
    <BrowserRouter>
      <Toaster richColors position="top-right" />
      <Routes>
        {/* Standalone routes — no Navbar/Footer */}
        <Route path="/player/movie/:imdbId" element={
          <Suspense fallback={<PageFallback />}><MoviePlayer /></Suspense>
        } />
        <Route path="/player/series/:imdbId" element={
          <Suspense fallback={<PageFallback />}><SeriesPlayer /></Suspense>
        } />
        <Route path="/player" element={
          <Suspense fallback={<PageFallback />}><Player /></Suspense>
        } />
        <Route path="/admin/login" element={
          <Suspense fallback={<PageFallback />}><AdminLogin /></Suspense>
        } />

        {/* Admin routes — protected, with ErrorBoundary */}
        <Route
          path="/admin"
          element={
            <ProtectedRoute>
              <ErrorBoundary>
                <Suspense fallback={<PageFallback />}>
                  <AdminDashboard />
                </Suspense>
              </ErrorBoundary>
            </ProtectedRoute>
          }
        />
        <Route
          path="/admin/import"
          element={
            <ProtectedRoute>
              <ErrorBoundary>
                <Suspense fallback={<PageFallback />}>
                  <AdminImport />
                </Suspense>
              </ErrorBoundary>
            </ProtectedRoute>
          }
        />
        <Route
          path="/admin/movies"
          element={
            <ProtectedRoute>
              <ErrorBoundary>
                <Suspense fallback={<PageFallback />}>
                  <ManageMovies />
                </Suspense>
              </ErrorBoundary>
            </ProtectedRoute>
          }
        />
        <Route
          path="/admin/series"
          element={
            <ProtectedRoute>
              <ErrorBoundary>
                <Suspense fallback={<PageFallback />}>
                  <ManageSeries />
                </Suspense>
              </ErrorBoundary>
            </ProtectedRoute>
          }
        />
        <Route
          path="/admin/tmdb"
          element={
            <ProtectedRoute>
              <ErrorBoundary>
                <Suspense fallback={<PageFallback />}>
                  <TmdbScraper />
                </Suspense>
              </ErrorBoundary>
            </ProtectedRoute>
          }
        />
        <Route
          path="/admin/sagas"
          element={
            <ProtectedRoute>
              <ErrorBoundary>
                <Suspense fallback={<PageFallback />}>
                  <SagaManager />
                </Suspense>
              </ErrorBoundary>
            </ProtectedRoute>
          }
        />
        <Route
          path="/admin/vidsrc-scanner"
          element={
            <ProtectedRoute>
              <ErrorBoundary>
                <Suspense fallback={<PageFallback />}>
                  <VidsrcScanner />
                </Suspense>
              </ErrorBoundary>
            </ProtectedRoute>
          }
        />
        <Route
          path="/admin/sport-channels"
          element={
            <ProtectedRoute>
              <ErrorBoundary>
                <Suspense fallback={<PageFallback />}>
                  <SportChannels />
                </Suspense>
              </ErrorBoundary>
            </ProtectedRoute>
          }
        />
        <Route
          path="/admin/event-channels"
          element={
            <ProtectedRoute>
              <ErrorBoundary>
                <Suspense fallback={<PageFallback />}>
                  <EventChannels />
                </Suspense>
              </ErrorBoundary>
            </ProtectedRoute>
          }
        />

        {/* Public site — Navbar + Footer + ErrorBoundary */}
        <Route element={<PublicLayout />}>
          <Route path="/" element={<Home />} />
          <Route path="/peliculas" element={<Movies />} />
          <Route path="/series" element={<SeriesList />} />
          <Route path="/deportes" element={<Sports />} />
          <Route path="/eventos" element={<Events />} />
          <Route path="/tv-en-vivo" element={<TvLive />} />
          <Route path="/pelicula/:id" element={<MovieDetail />} />
          <Route path="/serie/:id" element={<SeriesDetail />} />
          <Route path="/saga/:id" element={<SagaPage />} />
          <Route path="/search/:query" element={<Search />} />
          <Route path="*" element={<NotFound />} />
        </Route>
      </Routes>
    </BrowserRouter>
  );
}

