import { getToken } from "./auth";
import type { Movie, Series } from "./types";
import type { AutoImportStatus, VidsrcResult, RunImportResult, AdminStats } from "./types";

export const BASE_URL =
  (import.meta.env["VITE_API_URL"] as string | undefined) ||
  "https://cine-gratin.onrender.com";

// ── Generic helpers ───────────────────────────────────────────────────────────

export async function apiFetch<T>(path: string): Promise<T> {
  const res = await fetch(`${BASE_URL}${path}`);
  if (!res.ok) throw new Error(`API error ${res.status}: ${path}`);
  return res.json() as Promise<T>;
}

export async function apiPost<T>(path: string, body: unknown): Promise<T> {
  const res = await fetch(`${BASE_URL}${path}`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(body),
  });
  if (!res.ok) throw new Error(`API error ${res.status}: ${path}`);
  return res.json() as Promise<T>;
}

export async function apiPatch(path: string): Promise<void> {
  await fetch(`${BASE_URL}${path}`, { method: "PATCH" }).catch(() => {});
}

export function authHeaders(): Record<string, string> {
  const token = getToken();
  return token
    ? { "Content-Type": "application/json", Authorization: `Bearer ${token}` }
    : { "Content-Type": "application/json" };
}

export async function adminFetch<T>(path: string, options: RequestInit = {}): Promise<T> {
  const res = await fetch(`${BASE_URL}${path}`, {
    ...options,
    headers: { ...authHeaders(), ...options.headers },
  });
  if (!res.ok) {
    let msg = `Error ${res.status}`;
    try {
      const body = await res.json() as { error?: string; hint?: string };
      if (body.error) msg = body.hint ? `${body.error}\n\n${body.hint}` : body.error;
    } catch { /* keep default message */ }
    throw new Error(msg);
  }
  return res.json() as Promise<T>;
}

export async function adminPost<T>(path: string, body: unknown): Promise<T> {
  return adminFetch<T>(path, {
    method: "POST",
    body: JSON.stringify(body),
  });
}

export async function adminDelete(path: string): Promise<void> {
  const res = await fetch(`${BASE_URL}${path}`, {
    method: "DELETE",
    headers: authHeaders(),
  });
  if (!res.ok) throw new Error(`API error ${res.status}: ${path}`);
}

// ── Public endpoints ──────────────────────────────────────────────────────────

export const getMovies = (params?: { page?: number; limit?: number }): Promise<Movie[]> => {
  const query = new URLSearchParams();
  if (params?.page) query.append("page", params.page.toString());
  if (params?.limit) query.append("limit", params.limit.toString());
  const queryString = query.toString();
  return apiFetch(`/api/movies${queryString ? `?${queryString}` : ""}`);
};
export const getMovie = (id: string): Promise<Movie> => apiFetch(`/api/movies/${id}`);
export const getMovieByImdbId = (imdbId: string): Promise<Movie> => apiFetch(`/api/movies/${imdbId}`);
export const getSeries = (params?: { page?: number; limit?: number }): Promise<Series[]> => {
  const query = new URLSearchParams();
  if (params?.page) query.append("page", params.page.toString());
  if (params?.limit) query.append("limit", params.limit.toString());
  const queryString = query.toString();
  return apiFetch(`/api/series${queryString ? `?${queryString}` : ""}`);
};
export const getSeriesById = (id: string): Promise<Series> => apiFetch(`/api/series/${id}`);

export const searchMovies = (q: string, limit = 6): Promise<Movie[]> =>
  apiFetch(`/api/movies/search?q=${encodeURIComponent(q)}&limit=${limit}`);
export const searchSeries = (q: string, limit = 4): Promise<Series[]> =>
  apiFetch(`/api/series/search?q=${encodeURIComponent(q)}&limit=${limit}`);

export const trackMovieView = (id: string | number): Promise<void> =>
  apiPatch(`/api/movies/${id}/view`);
export const trackSeriesView = (id: string | number): Promise<void> =>
  apiPatch(`/api/series/${id}/view`);

// ── Admin endpoints ───────────────────────────────────────────────────────────

export const getAutoImportStatus = (): Promise<AutoImportStatus> =>
  adminFetch("/api/admin/auto-import/status");
export const toggleAutoImport = (enabled: boolean): Promise<{ enabled: boolean }> =>
  adminPost("/api/admin/auto-import/toggle", { enabled });
export const runAutoImport = (sources?: string[]): Promise<RunImportResult> =>
  adminPost("/api/admin/auto-import/run", { sources });

export interface IdImportResult {
  imdb_id: string;
  title: string | null;
  year?: number | null;
  status: "imported" | "existed" | "not_found" | "error";
  error?: string;
}

export interface ImportByIdsResponse {
  ok: boolean;
  results: IdImportResult[];
  summary: { imported: number; existed: number; not_found: number; error: number };
}

export const importByIds = (
  imdb_ids: string[],
  type: "movie" | "series"
): Promise<ImportByIdsResponse> =>
  adminPost("/api/admin/import-by-ids", { imdb_ids, type });

export const saveVidsrcResults = (
  results: { imdb_id: string; type: "movie" | "series"; available: boolean }[]
): Promise<VidsrcResult[]> =>
  adminPost("/api/admin/verify-vidsrc", { results });

// verifyVidsrc: descarga la lista pública de vidsrc.me y cruza con los ids dados
export const verifyVidsrc = async (
  imdb_ids: string[],
  type: "movie" | "series"
): Promise<VidsrcResult[]> => {
  // Descargar lista completa de vidsrc.me para este tipo
  const available = new Set<string>();
  const base = type === "series"
    ? "https://vidsrc.me/tvshows/latest/page-"
    : "https://vidsrc.me/movies/latest/page-";
  for (let page = 1; page <= 999; page++) {
    try {
      const res = await fetch(`${base}${page}.json`, { credentials: "omit" });
      if (!res.ok) break;
      const data = await res.json() as { imdb_id?: string }[];
      if (!Array.isArray(data) || data.length === 0) break;
      for (const item of data) { if (item.imdb_id) available.add(item.imdb_id); }
    } catch { break; }
  }

  const payload = imdb_ids.map((id) => ({ imdb_id: id, type, available: available.has(id) }));
  await saveVidsrcResults(payload).catch(() => {});
  return payload.map(({ imdb_id, available: av }) => ({ imdb_id, available: av }));
};

export const getAdminStats = (): Promise<AdminStats> =>
  adminFetch("/api/admin/stats");

export const deleteMovie = (id: string | number): Promise<void> =>
  adminDelete(`/api/admin/movies/${id}`);

export const deleteSeries = (id: string | number): Promise<void> =>
  adminDelete(`/api/admin/series/${id}`);

export const saveMovie = (movie: Partial<Movie>): Promise<Movie> =>
  adminPost(`/api/admin/movies${movie.id ? `/${movie.id}` : ""}`, movie);

export const saveSeries = (series: Partial<Series>): Promise<Series> =>
  adminPost(`/api/admin/series${series.id ? `/${series.id}` : ""}`, series);

export interface ScanNetworksResult {
  id: string | number;
  title: string;
  old_networks: string[];
  new_networks: string[];
  status: "updated" | "no_change" | "error";
  error?: string;
}

export interface ScanNetworksResponse {
  ok: boolean;
  results: ScanNetworksResult[];
  summary: { updated: number; no_change: number; error: number };
}

export const scanNetworks = (
  type: "movie" | "series",
  limit?: number
): Promise<ScanNetworksResponse> =>
  adminPost("/api/admin/scan-networks", { type, limit });


export interface CleanupResponse {
  ok: boolean;
  summary: { movies: number; series: number; total: number };
}

export interface UpdateCollectionItem {
  id: string;
  type: "movie" | "series";
  collection_id: number | null;
  collection_name: string | null;
}

export const updateCollection = (items: UpdateCollectionItem[]): Promise<{ ok: boolean; updated: number }> =>
  adminPost("/api/admin/update-collection", { items });

export const cleanupMissingImages = (type: "movie" | "series" | "all" = "all"): Promise<CleanupResponse> =>
  adminPost("/api/admin/cleanup-missing-images", { type });

export const cleanupNoVidsrc = (): Promise<CleanupResponse> =>
  adminPost("/api/admin/cleanup-no-vidsrc", {});

// ── TMDB Explorer ─────────────────────────────────────────────────────────────

export interface TmdbGenre {
  id: number;
  name: string;
}

export interface TmdbDiscoverItem {
  tmdb_id: number;
  title: string;
  year: string;
  poster_url: string;
  rating: number;
  vote_count: number;
  overview: string;
}

export interface TmdbDiscoverResult {
  ok: boolean;
  results: TmdbDiscoverItem[];
  total_results: number;
  total_pages: number;
  page: number;
}

export const getTmdbGenres = (type: "movie" | "series"): Promise<TmdbGenre[]> =>
  adminFetch(`/api/admin/tmdb-genres/${type}`);

export const tmdbDiscover = (params: {
  type: "movie" | "series";
  genre_ids?: string;
  year_from?: number;
  year_to?: number;
  sort_by?: string;
  language?: string;
  min_votes?: number;
  page?: number;
  count?: number;
}): Promise<TmdbDiscoverResult> =>
  adminPost("/api/admin/tmdb-discover", params);

export const importCollection = (
  collection_id: number
): Promise<{ ok: boolean; collection: string; imported: number; existed: number; total: number; titles: string[] }> =>
  adminPost("/api/admin/import-collection", { collection_id });

export const resetCollection = (
  collection_id: number
): Promise<{ ok: boolean; deleted_movies: number; deleted_series: number; total_deleted: number }> =>
  adminPost("/api/admin/reset-collection", { collection_id });

/** SSE URL for scan-collections-stream (attach token manually as query param) */
export const scanCollectionsStreamUrl = (collectionIds: number[]): string => {
  const base = (import.meta.env["VITE_API_URL"] as string | undefined) || "https://cine-gratin.onrender.com";
  return `${base}/api/admin/scan-collections-stream?ids=${collectionIds.join(",")}`;
};

/** SSE URL for sync-all-collections-stream */
export const syncAllCollectionsStreamUrl = (): string => {
  const base = (import.meta.env["VITE_API_URL"] as string | undefined) || "https://cine-gratin.onrender.com";
  return `${base}/api/admin/sync-all-collections-stream`;
};

export const importByTmdbIds = (
  tmdb_ids: number[],
  type: "movie" | "series"
): Promise<{ ok: boolean; summary: { imported: number; existed_or_error: number; total: number } }> =>
  adminPost("/api/admin/import-by-tmdb-ids", { tmdb_ids, type });

export interface TmdbCollectionSearchItem {
  id: number;
  name: string;
  poster_path: string | null;
  backdrop_path: string | null;
}

export const searchTmdbCollections = (query: string): Promise<TmdbCollectionSearchItem[]> =>
  apiFetch(`/api/tmdb/collections/search?query=${encodeURIComponent(query)}`);

export const getActiveSagas = (): Promise<number[]> =>
  adminFetch("/api/admin/active-sagas");

export const toggleSagaActive = (collection_id: number, active: boolean): Promise<{ ok: boolean }> =>
  adminPost("/api/admin/active-sagas", { collection_id, active });

export interface SagaMember {
  id: string | number;
  title: string;
  poster_url: string;
  year: string;
  type: "movie" | "series";
}

export const getSagaMembers = (collection_id: number): Promise<SagaMember[]> =>
  adminFetch(`/api/admin/saga-members/${collection_id}`);

export const manageSagaMember = (body: {
  id: string | number;
  type: "movie" | "series";
  collection_id: number | null;
  collection_name: string | null;
  action: "add" | "remove";
}): Promise<{ ok: boolean }> =>
  adminPost("/api/admin/saga-member", body);

// ── Saga Config CRUD ──────────────────────────────────────────────────────────

export interface SagaConfigRow {
  id: string;
  label: string;
  collection_id: number | null;
  keywords: string[];
  sort_order: number;
  active: boolean;
}

export const getSagaConfig = (): Promise<SagaConfigRow[]> =>
  adminFetch("/api/admin/saga-config");

export const createSagaConfig = (data: Omit<SagaConfigRow, "sort_order"> & { sort_order?: number }): Promise<SagaConfigRow> =>
  adminPost("/api/admin/saga-config", data);

export const updateSagaConfig = (id: string, data: Partial<SagaConfigRow>): Promise<SagaConfigRow> =>
  adminFetch(`/api/admin/saga-config/${id}`, {
    method: "PUT",
    body: JSON.stringify(data),
  });

export const deleteSagaConfig = (id: string): Promise<{ ok: boolean; deleted: string }> =>
  adminFetch(`/api/admin/saga-config/${id}`, { method: "DELETE" });

export const seedSagaConfig = (): Promise<{ ok: boolean; inserted: number }> =>
  adminPost("/api/admin/saga-config/seed", {});

import { useQuery } from "@tanstack/react-query";
import { apiFetch } from "@/lib/api";
import type { Movie, Series } from "@/lib/types";

export function useFeaturedMovies() {
  return useQuery<Movie[]>({
    queryKey: ["movies", "featured"],
    queryFn: () => apiFetch("/api/movies/featured"),
    staleTime: 5 * 60 * 1000,
  });
}

export function useMovies(page?: number, limit?: number) {
  const p = Number(page) || 1;
  const l = Number(limit) || 20;
  return useQuery<Movie[]>({
    queryKey: ["movies", p, l],
    queryFn: () => apiFetch(`/api/movies?page=${p}&limit=${l}`),
    staleTime: 5 * 60 * 1000,
  });
}

export function useMovie(id: string) {
  return useQuery<Movie>({
    queryKey: ["movie", id],
    queryFn: () => apiFetch(`/api/movies/${id}`),
    staleTime: 10 * 60 * 1000,
    enabled: Boolean(id),
  });
}

export function useSeriesList(page?: number, limit?: number) {
  const p = Number(page) || 1;
