import { useState, useEffect } from "react";
import { KeyIcon } from "./icons";

interface Props {
  getSettings: () => Promise<Record<string, string>>;
  saveSettings: (data: { youtube_api_key: string }) => Promise<{ ok: boolean }>;
}

export default function YouTubeSettingsSection({ getSettings, saveSettings }: Props) {
  const [apiKey, setApiKey] = useState("");
  const [saved, setSaved] = useState(false);
  const [loading, setLoading] = useState(false);
  const [show, setShow] = useState(false);

  useEffect(() => {
    getSettings()
      .then((s) => {
        if (s["youtube_api_key"]) setApiKey(s["youtube_api_key"]);
      })
      .catch(() => {});
  }, [getSettings]);

  const handleSave = async () => {
    if (!apiKey.trim()) return;
    setLoading(true);
    try {
      await saveSettings({ youtube_api_key: apiKey.trim() });
      setSaved(true);
      setTimeout(() => setSaved(false), 2500);
    } catch {
      // silent
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="bg-brand-card border border-brand-border rounded-2xl p-6 space-y-4">
      <div className="flex items-center gap-2">
        <KeyIcon />
        <h2 className="text-white font-bold text-base">API Key de YouTube</h2>
      </div>
      <p className="text-gray-500 text-sm">
        Necesitas una API Key de{" "}
        <a
          href="https://console.cloud.google.com"
          target="_blank"
          rel="noreferrer"
          className="text-brand-red hover:underline"
        >
          Google Cloud Console
        </a>{" "}
        con <strong className="text-gray-400">YouTube Data API v3</strong> habilitada.
      </p>
      <div className="flex gap-2">
        <input
          type={show ? "text" : "password"}
          value={apiKey}
          onChange={(e) => setApiKey(e.target.value)}
          placeholder="AIzaSy..."
          className="flex-1 bg-brand-surface border border-brand-border rounded-lg px-4 py-2.5 text-gray-200 placeholder-gray-600 text-sm font-mono focus:outline-none focus:border-gray-500"
        />
        <button
          onClick={() => setShow((v) => !v)}
          className="px-3 text-gray-500 hover:text-gray-300 border border-brand-border rounded-lg bg-brand-surface transition-colors text-xs"
        >
          {show ? "Ocultar" : "Ver"}
        </button>
        <button
          onClick={handleSave}
          disabled={loading || !apiKey.trim()}
          className="flex items-center gap-2 bg-brand-red hover:bg-red-700 disabled:opacity-40 disabled:cursor-not-allowed text-white font-bold py-2 px-4 rounded-lg transition-colors text-sm"
        >
          {loading ? (
            <span className="w-4 h-4 border-2 border-white border-t-transparent rounded-full animate-spin block" />
          ) : saved ? (
            "✓ Guardada"
          ) : (
            "Guardar"
          )}
        </button>
      </div>
    </div>
  );
}

import { useState, useEffect, useCallback } from "react";
import { SyncIcon, PlusIcon, TrashIcon } from "./icons";
import type { Channel, SyncResult } from "@/lib/channels-api";

interface Props {
  variant: "list" | "table";
  description: string;
  defaultKeyword: string;
  channelNamePlaceholder: string;
  channelUrlPlaceholder: string;
  keywordPlaceholder: string;
  emptyMessage: string;
  getChannels: () => Promise<Channel[]>;
  addChannel: (data: { name: string; url: string; keyword?: string }) => Promise<Channel>;
  deleteChannel: (id: number) => Promise<void>;
  syncChannel: (id: number) => Promise<SyncResult>;
  syncAllChannels: () => Promise<SyncResult>;
  onSynced: () => void;
}

export default function YouTubeChannelsSection({
  variant,
  description,
  defaultKeyword,
  channelNamePlaceholder,
  channelUrlPlaceholder,
  keywordPlaceholder,
  emptyMessage,
  getChannels,
  addChannel,
  deleteChannel,
  syncChannel,
  syncAllChannels,
  onSynced,
}: Props) {
  const [channels, setChannels] = useState<Channel[]>([]);
  const [loading, setLoading] = useState(true);
  const [syncing, setSyncing] = useState<number | "all" | null>(null);
  const [syncResult, setSyncResult] = useState<{ msg: string; error?: boolean } | null>(null);

  // Add form state
  const [form, setForm] = useState({ name: "", url: "", keyword: defaultKeyword });
  const [adding, setAdding] = useState(false);
  const [formError, setFormError] = useState("");

  const load = useCallback(async () => {
    setLoading(true);
    try {
      setChannels(await getChannels());
    } catch {
      // silent
    } finally {
      setLoading(false);
    }
  }, [getChannels]);

  useEffect(() => {
    load();
  }, [load]);

  // Keep defaultKeyword in sync when prop changes
  useEffect(() => {
    setForm((f) => ({ ...f, keyword: defaultKeyword }));
  }, [defaultKeyword]);

  const handleAdd = async () => {
    if (!form.name.trim() || !form.url.trim()) {
      setFormError("Nombre y URL son obligatorios.");
      return;
    }
    setAdding(true);
    setFormError("");
    try {
      await addChannel(form);
      setForm({ name: "", url: "", keyword: defaultKeyword });
      await load();
    } catch (e: unknown) {
      setFormError(e instanceof Error ? e.message : "Error al añadir canal.");
    } finally {
      setAdding(false);
    }
  };

  const handleDelete = async (id: number) => {
    const msg = variant === "table"
      ? "¿Eliminar este canal y todos sus partidos?"
      : "¿Eliminar este canal y todos sus eventos?";
    if (!confirm(msg)) return;
    try {
      await deleteChannel(id);
      await load();
      onSynced();
    } catch {
      // silent
    }
  };

  const handleSync = async (id: number) => {
    setSyncing(id);
    setSyncResult(null);
    try {
      const r = await syncChannel(id);
      setSyncResult({
        msg: `✓ ${r.imported} importados, ${r.existed} ya existían`,
      });
      onSynced();
    } catch (e: unknown) {
      setSyncResult({
        msg: e instanceof Error ? e.message : "Error al sincronizar",
        error: true,
      });
    } finally {
      setSyncing(null);
    }
  };

  const handleSyncAll = async () => {
    setSyncing("all");
    setSyncResult(null);
    try {
      const r = await syncAllChannels();
      setSyncResult({
        msg: `✓ Sincronización completa: ${r.imported} importados, ${r.existed} ya existían${
          r.errors?.length ? ` — ${r.errors.length} errores` : ""
        }`,
      });
      onSynced();
    } catch (e: unknown) {
      setSyncResult({
        msg: e instanceof Error ? e.message : "Error al sincronizar",
        error: true,
      });
    } finally {
      setSyncing(null);
    }
  };

  // ─── Shared form ──────────────────────────────────────────────────────────

  const addForm = (
    <div className="bg-brand-surface border border-brand-border rounded-xl p-4 space-y-3">
      <p className="text-gray-400 text-xs font-semibold uppercase tracking-wider">
        Añadir nuevo canal
      </p>
      <div className="grid grid-cols-1 sm:grid-cols-3 gap-2">
        <input
          type="text"
          placeholder={channelNamePlaceholder}
          value={form.name}
          onChange={(e) => setForm((f) => ({ ...f, name: e.target.value }))}
          className="bg-brand-card border border-brand-border rounded-lg px-3 py-2 text-gray-200 placeholder-gray-600 text-sm focus:outline-none focus:border-gray-500"
        />
        <input
          type="text"
          placeholder={channelUrlPlaceholder}
          value={form.url}
          onChange={(e) => setForm((f) => ({ ...f, url: e.target.value }))}
          className="bg-brand-card border border-brand-border rounded-lg px-3 py-2 text-gray-200 placeholder-gray-600 text-sm font-mono focus:outline-none focus:border-gray-500"
        />
        <input
          type="text"
          placeholder={keywordPlaceholder}
          value={form.keyword}
          onChange={(e) => setForm((f) => ({ ...f, keyword: e.target.value }))}
          className="bg-brand-card border border-brand-border rounded-lg px-3 py-2 text-gray-200 placeholder-gray-600 text-sm focus:outline-none focus:border-gray-500"
        />
      </div>
      {formError && <p className="text-red-400 text-xs">{formError}</p>}
      <button
        onClick={handleAdd}
        disabled={adding}
        className="flex items-center gap-2 bg-brand-red hover:bg-red-700 disabled:opacity-40 text-white font-bold py-2 px-4 rounded-lg transition-colors text-sm"
      >
        {adding ? (
          <span className="w-4 h-4 border-2 border-white border-t-transparent rounded-full animate-spin block" />
        ) : (
          <PlusIcon />
        )}
        Añadir canal
      </button>
    </div>
  );

  // ─── Sync result banner ───────────────────────────────────────────────────

  const syncBanner = syncResult && (
    <div
      className={`text-sm font-medium p-3 rounded-lg border ${
        syncResult.error
          ? "bg-red-900/30 border-red-800/40 text-red-400"
          : "bg-green-900/30 border-green-800/40 text-green-400"
      }`}
    >
      {syncResult.msg}
    </div>
  );

  // ─── List variant ─────────────────────────────────────────────────────────

  const renderList = () => (
    <div className="space-y-2">
      {channels.map((ch) => (
        <div
          key={ch.id}
          className="flex items-center justify-between bg-brand-surface border border-brand-border rounded-lg p-3"
        >
          <div className="min-w-0 flex-1">
            <p className="text-white font-semibold text-sm">{ch.name}</p>
            <p className="text-gray-500 text-xs truncate">{ch.url}</p>
            <p className="text-gray-600 text-xs">Keyword: {ch.keyword}</p>
          </div>
          <div className="flex items-center gap-2 flex-shrink-0 ml-3">
            <button
              onClick={() => handleSync(ch.id)}
              disabled={syncing !== null}
              className="flex items-center gap-1 bg-green-900/30 border border-green-800/40 hover:bg-green-900/50 disabled:opacity-40 text-green-400 font-bold py-1 px-2 rounded text-xs transition-colors"
            >
              {syncing === ch.id ? (
                <span className="w-3 h-3 border border-green-400 border-t-transparent rounded-full animate-spin block" />
              ) : (
                <SyncIcon />
              )}
              Sincronizar
            </button>
            <button
              onClick={() => handleDelete(ch.id)}
              disabled={syncing !== null}
              className="flex items-center gap-1 bg-red-900/30 border border-red-800/40 hover:bg-red-900/50 disabled:opacity-40 text-red-400 font-bold py-1 px-2 rounded text-xs transition-colors"
            >
              <TrashIcon />
            </button>
          </div>
        </div>
      ))}
    </div>
  );

  // ─── Table variant ────────────────────────────────────────────────────────

  const renderTable = () => (
    <div className="border border-brand-border rounded-xl overflow-hidden">
      <table className="w-full text-sm">
        <thead>
          <tr className="border-b border-brand-border bg-brand-surface/50">
            <th className="text-left px-4 py-3 text-gray-500 text-xs uppercase tracking-wider font-medium">
              Canal
            </th>
            <th className="text-left px-4 py-3 text-gray-500 text-xs uppercase tracking-wider font-medium hidden sm:table-cell">
              Keyword
            </th>
            <th className="text-right px-4 py-3 text-gray-500 text-xs uppercase tracking-wider font-medium">
              Acciones
            </th>
          </tr>
        </thead>
        <tbody className="divide-y divide-brand-border">
          {channels.map((ch) => (
            <tr key={ch.id} className="hover:bg-brand-surface/30 transition-colors">
              <td className="px-4 py-3">
                <div className="text-gray-200 font-medium text-sm">{ch.name}</div>
                <div className="text-gray-600 text-xs font-mono truncate max-w-[220px]">
                  {ch.url}
                </div>
              </td>
              <td className="px-4 py-3 hidden sm:table-cell">
                <span className="text-xs bg-brand-surface border border-brand-border text-gray-400 px-2 py-1 rounded">
                  {ch.keyword}
                </span>
              </td>
              <td className="px-4 py-3 text-right">
                <div className="flex items-center justify-end gap-2">
                  <button
                    onClick={() => handleSync(ch.id)}
                    disabled={syncing !== null}
                    className="flex items-center gap-1.5 bg-brand-surface border border-brand-border hover:border-gray-500 disabled:opacity-40 text-gray-300 hover:text-white text-xs font-semibold py-1.5 px-3 rounded-lg transition-colors"
                  >
                    {syncing === ch.id ? (
                      <span className="w-3.5 h-3.5 border-2 border-gray-400 border-t-transparent rounded-full animate-spin block" />
                    ) : (
                      <SyncIcon />
                    )}
                    Sincronizar
                  </button>
                  <button
                    onClick={() => handleDelete(ch.id)}
                    className="p-1.5 text-gray-600 hover:text-red-400 transition-colors rounded-lg hover:bg-red-900/20"
                  >
                    <TrashIcon />
                  </button>
                </div>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );

  // ─── Loading / Empty / Content ────────────────────────────────────────────

  const renderBody = () => {
    if (loading) {
      return (
        <div className="flex justify-center py-8">
          <span className="w-5 h-5 rounded-full border-2 border-brand-red border-t-transparent animate-spin block" />
        </div>
      );
    }

    if (channels.length === 0) {
      return <p className="text-gray-500 text-sm text-center py-8">{emptyMessage}</p>;
    }

    return variant === "table" ? renderTable() : renderList();
  };

  // ─── Main render ──────────────────────────────────────────────────────────

  return (
    <div className="bg-brand-card border border-brand-border rounded-2xl p-6 space-y-5">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-white font-bold text-base mb-1">Canales de YouTube</h2>
          <p className="text-gray-500 text-sm">{description}</p>
        </div>
        {channels.length > 0 && (
          <button
            onClick={handleSyncAll}
            disabled={syncing !== null}
            className="flex items-center gap-2 bg-green-900/30 border border-green-800/40 hover:bg-green-900/50 disabled:opacity-40 text-green-400 font-bold py-2 px-4 rounded-lg transition-colors text-sm"
          >
            {syncing === "all" ? (
              <span className="w-4 h-4 border-2 border-green-400 border-t-transparent rounded-full animate-spin block" />
            ) : (
              <SyncIcon />
            )}
            Sincronizar todos
          </button>
        )}
      </div>

      {addForm}
      {syncBanner}
      {renderBody()}
    </div>
  );
}

import { useState, useEffect, useCallback } from "react";
import AdminLayout from "@/components/admin/AdminLayout";
import YouTubeSettingsSection from "@/components/admin/YouTubeSettingsSection";
import YouTubeChannelsSection from "@/components/admin/YouTubeChannelsSection";
import { TrashIcon } from "@/components/admin/icons";
import {
  getEventChannels,
  addEventChannel,
  deleteEventChannel,
  syncEventChannel,
  syncAllEventChannels,
  getEventsSettings,
  saveEventsSettings,
  deleteEvent,
  getEvents,
  type Event,
} from "@/lib/events-api";

// ─── Events section ───────────────────────────────────────────────────────────

function EventsSection() {
  const [events, setEvents] = useState<Event[]>([]);
  const [loading, setLoading] = useState(true);
  const [deleting, setDeleting] = useState<number | null>(null);

  const load = useCallback(async () => {
    setLoading(true);
    try {
      setEvents(await getEvents({ limit: 100 }));
    } catch {
      // silent
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    load();
  }, [load]);

  const handleDelete = async (id: number) => {
    if (!confirm("¿Eliminar este evento?")) return;
    setDeleting(id);
    try {
      await deleteEvent(id);
      await load();
    } catch {
      // silent
    } finally {
      setDeleting(null);
    }
  };

  return (
    <div className="bg-brand-card border border-brand-border rounded-2xl p-6 space-y-4">
      <div>
        <h2 className="text-white font-bold text-base mb-1">Eventos Importados</h2>
        <p className="text-gray-500 text-sm">
          {events.length} eventos disponibles (mínimo 30 minutos)
        </p>
      </div>

      {loading ? (
        <div className="text-center py-8">
          <div className="w-5 h-5 rounded-full border-2 border-brand-red border-t-transparent animate-spin mx-auto" />
        </div>
      ) : events.length === 0 ? (
        <p className="text-gray-500 text-sm text-center py-8">No hay eventos importados.</p>
      ) : (
        <div className="max-h-96 overflow-y-auto space-y-2">
          {events.map((event) => (
            <div
              key={event.id}
              className="flex items-center justify-between bg-brand-surface border border-brand-border rounded-lg p-3"
            >
              <div className="min-w-0 flex-1">
                <p className="text-white font-semibold text-sm line-clamp-1">{event.title}</p>
                <p className="text-gray-500 text-xs">{event.channel_name}</p>
              </div>
              <button
                onClick={() => handleDelete(event.id)}
                disabled={deleting !== null}
                className="flex items-center gap-1 bg-red-900/30 border border-red-800/40 hover:bg-red-900/50 disabled:opacity-40 text-red-400 font-bold py-1 px-2 rounded text-xs transition-colors flex-shrink-0 ml-3"
              >
                {deleting === event.id ? (
                  <span className="w-3 h-3 border border-red-400 border-t-transparent rounded-full animate-spin block" />
                ) : (
                  <TrashIcon />
                )}
              </button>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

// ─── Main component ───────────────────────────────────────────────────────────

export default function EventChannels() {
  const [refreshKey, setRefreshKey] = useState(0);

  return (
    <AdminLayout>
      <div className="space-y-6">
        <div>
          <h1 className="text-3xl font-black text-white">Gestionar Eventos</h1>
          <p className="text-gray-400 text-sm mt-1">
            Importa eventos de YouTube (conciertos, festivales, etc.) de mínimo 30 minutos.
          </p>
        </div>

        <YouTubeSettingsSection
          getSettings={getEventsSettings}
          saveSettings={saveEventsSettings}
        />
        <YouTubeChannelsSection
          variant="list"
          description="Añade canales y sincroniza sus eventos automáticamente."
          defaultKeyword="CONCIERTO"
          channelNamePlaceholder="Nombre (ej: Vivo Conciertos)"
          channelUrlPlaceholder="https://www.youtube.com/@VivoConciertos"
          keywordPlaceholder='Keyword (por defecto "CONCIERTO")'
          emptyMessage="No hay canales añadidos."
          getChannels={getEventChannels}
          addChannel={addEventChannel}
          deleteChannel={deleteEventChannel}
          syncChannel={syncEventChannel}
          syncAllChannels={syncAllEventChannels}
          onSynced={() => setRefreshKey((k) => k + 1)}
        />
        <EventsSection key={refreshKey} />
      </div>
    </AdminLayout>
  );
}

import { useState, useEffect, useCallback } from "react";
import AdminLayout from "@/components/admin/AdminLayout";
import YouTubeSettingsSection from "@/components/admin/YouTubeSettingsSection";
import YouTubeChannelsSection from "@/components/admin/YouTubeChannelsSection";
import { TrashIcon } from "@/components/admin/icons";
import {
  getSportChannels,
  addSportChannel,
  deleteSportChannel,
  syncSportChannel,
  syncAllSportChannels,
  getSportsSettings,
  saveSportsSettings,
  deleteSportMatch,
  getSportMatches,
  type SportMatch,
} from "@/lib/sports-api";

// ─── Matches section ──────────────────────────────────────────────────────────

function MatchesSection({ refreshKey }: { refreshKey: number }) {
  const [matches, setMatches] = useState<SportMatch[]>([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState("");
  const [query, setQuery] = useState("");

  const load = useCallback(async () => {
    setLoading(true);
    try {
      const data = await getSportMatches({ q: query || undefined, limit: 100 });
      setMatches(data);
    } catch {
      // silent
    } finally {
      setLoading(false);
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [query, refreshKey]);

  useEffect(() => {
    load();
  }, [load]);

  const handleDelete = async (id: number) => {
    if (!confirm("¿Eliminar este partido del catálogo?")) return;
    await deleteSportMatch(id);
    setMatches((prev) => prev.filter((m) => m.id !== id));
  };

  return (
    <div className="bg-brand-card border border-brand-border rounded-2xl p-6 space-y-5">
      <div className="flex items-center justify-between flex-wrap gap-3">
        <div>
          <h2 className="text-white font-bold text-base mb-1">
            Partidos importados{" "}
            <span className="text-gray-500 font-normal text-sm">({matches.length})</span>
          </h2>
          <p className="text-gray-500 text-sm">
            Todos los partidos guardados en la base de datos.
          </p>
        </div>
        <div className="flex gap-2">
          <input
            type="text"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            onKeyDown={(e) => e.key === "Enter" && setQuery(search)}
            placeholder="Buscar partido..."
            className="bg-brand-surface border border-brand-border rounded-lg px-3 py-2 text-gray-200 placeholder-gray-600 text-sm focus:outline-none focus:border-gray-500 w-48"
          />
          <button
            onClick={() => setQuery(search)}
            className="bg-brand-surface border border-brand-border hover:border-gray-500 text-gray-300 hover:text-white text-sm font-semibold py-2 px-3 rounded-lg transition-colors"
          >
            Buscar
          </button>
          {query && (
            <button
              onClick={() => { setSearch(""); setQuery(""); }}
              className="text-gray-500 hover:text-gray-300 text-sm transition-colors"
            >
              Limpiar
            </button>
          )}
        </div>
      </div>

      {loading ? (
        <div className="flex justify-center py-8">
          <span className="w-8 h-8 border-2 border-brand-red border-t-transparent rounded-full animate-spin block" />
        </div>
      ) : matches.length === 0 ? (
        <div className="text-center py-8 text-gray-600 text-sm">
          {query ? "No se encontraron partidos con ese filtro." : "No hay partidos importados aún."}
        </div>
      ) : (
        <div className="border border-brand-border rounded-xl overflow-hidden">
          <div className="max-h-[500px] overflow-y-auto divide-y divide-brand-border">
            {matches.map((m) => (
              <div
                key={m.id}
                className="flex items-center gap-4 px-4 py-3 hover:bg-brand-surface/30 transition-colors"
              >
                {m.thumbnail && (
                  <img
                    src={m.thumbnail}
                    alt=""
                    className="w-16 h-10 object-cover rounded flex-shrink-0 bg-brand-surface"
                  />
                )}
                <div className="flex-1 min-w-0">
                  <div className="text-gray-200 text-sm font-medium truncate">{m.title}</div>
                  <div className="text-gray-600 text-xs flex gap-3 mt-0.5">
                    <span>{m.channel_name}</span>
                    {m.published_at && (
                      <span>{new Date(m.published_at).toLocaleDateString("es-ES")}</span>
                    )}
                  </div>
                </div>
                <div className="flex items-center gap-2 flex-shrink-0">
                  <a
                    href={`https://www.youtube.com/watch?v=${m.yt_id}`}
                    target="_blank"
                    rel="noreferrer"
                    className="text-xs text-gray-500 hover:text-brand-red transition-colors font-mono"
                  >
                    {m.yt_id}
                  </a>
                  <button
                    onClick={() => handleDelete(m.id)}
                    className="p-1.5 text-gray-600 hover:text-red-400 transition-colors rounded-lg hover:bg-red-900/20"
                  >
                    <TrashIcon />
                  </button>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}

// ─── Page ─────────────────────────────────────────────────────────────────────

export default function SportChannels() {
  const [refreshKey, setRefreshKey] = useState(0);

  return (
    <AdminLayout>
      <div className="space-y-6">
        <div>
          <h1 className="text-2xl font-black text-white">⚽ Deportes — Partidos de Fútbol</h1>
          <p className="text-gray-500 text-sm mt-0.5">
            Importa partidos completos desde canales de YouTube automáticamente.
          </p>
        </div>

        <YouTubeSettingsSection
          getSettings={getSportsSettings}
          saveSettings={saveSportsSettings}
        />
        <YouTubeChannelsSection
          variant="table"
          description="Añade canales y sincroniza sus partidos completos automáticamente."
          defaultKeyword="FULL MATCH"
          channelNamePlaceholder="Nombre (ej: UEFA)"
          channelUrlPlaceholder="https://www.youtube.com/@UEFA"
          keywordPlaceholder='Keyword (por defecto "FULL MATCH")'
          emptyMessage="No hay canales configurados. Añade uno arriba."
          getChannels={getSportChannels}
          addChannel={addSportChannel}
          deleteChannel={deleteSportChannel}
          syncChannel={syncSportChannel}
          syncAllChannels={syncAllSportChannels}
          onSynced={() => setRefreshKey((k) => k + 1)}
        />
        <MatchesSection refreshKey={refreshKey} />
      </div>
    </AdminLayout>
  );
}

